/**
 * @guilherme/agent-sdk/react/useAgentChat
 *
 * Extended hook for AgentChat with confirmation dialogs,
 * localStorage persistence, and error classification.
 */

import { useState, useCallback, useEffect, useRef } from 'react';
import type { ChatMessage } from './useChat';
import type { SessionMetadata } from '../../core/history';

export interface AgentChatMessage extends ChatMessage {
  /** Whether this message has an error */
  isError?: boolean;
  /** Type of error for specialized handling */
  errorType?: 'api' | 'tool' | 'unknown';
  /** Pending confirmation dialog */
  pendingConfirm?: { message: string; confirmId: string };
}

export interface UseAgentChatOptions {
  /** API endpoint */
  api?: string;
  /** Session ID for persistence */
  sessionId?: string;
  /** Storage key prefix for localStorage */
  storageKey?: string;
  /** Enable localStorage persistence */
  persist?: boolean;
  /** Callback when tool is executed */
  onToolExecuted?: () => void;
  /** Custom headers */
  headers?: Record<string, string>;
  /** Custom body fields */
  body?: Record<string, any>;
  /** Session management configuration */
  sessionManagement?: {
    level: 'none' | 'basic' | 'full';
    maxSessions?: number;
    persistDays?: number;
  };
}

export interface UseAgentChatReturn {
  /** Array of chat messages */
  messages: AgentChatMessage[];
  /** Current input value */
  input: string;
  /** Set input value */
  setInput: (value: string) => void;
  /** Whether a request is in progress */
  isLoading: boolean;
  /** Current error */
  error: Error | null;
  /** Send a message */
  sendMessage: (content?: string) => Promise<void>;
  /** Stop current streaming */
  stop: () => void;
  /** Set messages directly */
  setMessages: (messages: AgentChatMessage[] | ((prev: AgentChatMessage[]) => AgentChatMessage[])) => void;
  /** Clear all messages */
  clearMessages: () => void;
  /** Handle input change */
  handleInputChange: (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => void;
  /** Handle form submit */
  handleSubmit: (e: React.FormEvent) => void;
  /** Handle confirmation response */
  handleConfirm: (confirmId: string, confirmed: boolean) => Promise<void>;
  /** Session ID */
  sessionId: string;
  /** Context usage information */
  contextUsage: { tokens: number; maxTokens: number; messageCount: number; usagePercent: number } | null;
  /** Update context usage (e.g. after compact) */
  setContextUsage: React.Dispatch<React.SetStateAction<{ tokens: number; maxTokens: number; messageCount: number; usagePercent: number } | null>>;
  /** Set session ID (for switching sessions) */
  setSessionId: (id: string) => void;
  /** Session management */
  sessions: SessionMetadata[];
  showSessions: boolean;
  setShowSessions: React.Dispatch<React.SetStateAction<boolean>>;
  sessionsLoading: boolean;
  loadSessions: () => Promise<void>;
  deleteSession: (sessionId: string) => Promise<void>;
  switchSession: (sessionId: string) => void;
}

function generateId(): string {
  return `${Date.now()}-${Math.random().toString(36).slice(2, 11)}`;
}

/**
 * Hook for AgentChat with extended features
 */
export function useAgentChat(options: UseAgentChatOptions = {}): UseAgentChatReturn {
  const {
    api = '/api/chat',
    sessionId: propSessionId,
    storageKey = 'agent_chat',
    persist = true,
    onToolExecuted,
    headers,
    body,
    sessionManagement,
  } = options;

  // Session management state
  const [sessions, setSessions] = useState<SessionMetadata[]>([]);
  const [showSessions, setShowSessions] = useState(false);
  const [sessionsLoading, setSessionsLoading] = useState(false);

  // Generate or use provided session ID (mutable for session switching)
  const [sessionId, setSessionId] = useState(() => {
    if (propSessionId) return propSessionId;
    if (typeof window === 'undefined') return `session-${Date.now()}`;
    const params = new URLSearchParams(window.location.search);
    const existing = params.get('sessionId');
    if (existing) return existing;
    return `session-${Date.now()}-${Math.random().toString(36).slice(2)}`;
  });

  const storageKeyRef = `${storageKey}_${sessionId}`;

  // Load initial messages from localStorage
  const initialMessages = useState<AgentChatMessage[]>(() => {
    if (!persist || typeof window === 'undefined') return [];
    try {
      const stored = localStorage.getItem(storageKeyRef);
      return stored ? JSON.parse(stored) : [];
    } catch {
      return [];
    }
  })[0];

  const [messages, setMessages] = useState<AgentChatMessage[]>(initialMessages);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<Error | null>(null);
  const [contextUsage, setContextUsage] = useState<{
    tokens: number;
    maxTokens: number;
    messageCount: number;
    usagePercent: number;
  } | null>(null);

  // Pending confirmations map
  const pendingConfirmsRef = useRef<Map<string, { resolve: (confirmed: boolean) => void }>>(new Map());
  const abortControllerRef = useRef<AbortController | null>(null);

  // Persist messages to localStorage
  useEffect(() => {
    if (!persist || typeof window === 'undefined') return;
    try {
      localStorage.setItem(storageKeyRef, JSON.stringify(messages));
    } catch {}
  }, [messages, storageKeyRef, persist]);

  const sendMessage = useCallback(async (content?: string) => {
    const messageContent = content ?? input;
    if (!messageContent.trim() || isLoading) return;

    setInput('');
    setIsLoading(true);
    setError(null);

    // Create placeholder for assistant message
    const userMessageId = generateId();
    const assistantId = generateId();
    setMessages(prev => [
      ...prev,
      {
        id: userMessageId,
        role: 'user',
        content: messageContent,
      },
      {
        id: assistantId,
        role: 'assistant',
        content: '',
        isStreaming: true,
      },
    ]);

    abortControllerRef.current = new AbortController();

    try {
      const response = await fetch(api, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          ...headers,
        },
        body: JSON.stringify({
          message: messageContent,
          sessionId,
          ...body,
        }),
        signal: abortControllerRef.current.signal,
      });

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(errorText);
      }

      const reader = response.body!.getReader();
      const decoder = new TextDecoder();
      let buffer = '';
      let toolCalls: any[] = [];
      let statusSteps: string[] = [];

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop() ?? '';

        for (const line of lines) {
          if (!line.startsWith('data: ')) continue;
          try {
            const data = JSON.parse(line.slice(6));

            switch (data.type) {
              case 'token':
                setMessages(prev => prev.map(m =>
                  m.id === assistantId
                    ? { ...m, content: m.content + data.content }
                    : m
                ));
                break;

              case 'status':
                statusSteps.push(data.text);
                setMessages(prev => prev.map(m =>
                  m.id === assistantId
                    ? { ...m, statusSteps: [...statusSteps] }
                    : m
                ));
                break;

              case 'tool_call':
                toolCalls.push(data.toolCall);
                break;

              case 'confirm':
                setMessages(prev => prev.map(m =>
                  m.id === assistantId
                    ? { ...m, pendingConfirm: { message: data.message, confirmId: data.confirmId } }
                    : m
                ));
                // Wait for confirmation
                const confirmed = await new Promise<boolean>((resolve) => {
                  pendingConfirmsRef.current.set(data.confirmId, { resolve });
                });
                // Send confirmation response
                await fetch(api, {
                  method: 'POST',
                  headers: { 'Content-Type': 'application/json', ...headers },
                  body: JSON.stringify({ sessionId, confirmId: data.confirmId, confirmed }),
                });
                // Clear pending confirm
                setMessages(prev => prev.map(m =>
                  m.id === assistantId
                    ? { ...m, pendingConfirm: undefined }
                    : m
                ));
                if (!confirmed) {
                  // User cancelled
                  setMessages(prev => prev.map(m =>
                    m.id === assistantId
                      ? { ...m, isStreaming: false, content: 'Ação cancelada.' }
                      : m
                  ));
                  return;
                }
                break;

              case 'context_usage':
                setContextUsage({
                  tokens: data.tokens,
                  maxTokens: data.maxTokens,
                  messageCount: data.messageCount,
                  usagePercent: data.usagePercent,
                });
                break;

              case 'done':
                const finalToolCalls = toolCalls.length > 0 ? toolCalls : (data.toolCalls ?? []);
                setMessages(prev => prev.map(m =>
                  m.id === assistantId
                    ? { ...m, isStreaming: false, toolCalls: finalToolCalls }
                    : m
                ));
                if (finalToolCalls.length > 0) {
                  onToolExecuted?.();
                }
                break;

              case 'error':
                const raw: string = data.error || '';
                const isRateLimit =
                  raw.includes('429') ||
                  raw.includes('1302') ||
                  raw.toLowerCase().includes('rate limit');
                const errorType = isRateLimit ? 'api' : 'unknown';
                const friendlyMsg = isRateLimit
                  ? 'Atingi o limite de requisições. Aguarde alguns segundos.'
                  : 'Algo deu errado.';
                setMessages(prev => prev.map(m =>
                  m.id === assistantId
                    ? { ...m, content: friendlyMsg, isStreaming: false, isError: true, errorType }
                    : m
                ));
                break;
            }
          } catch {}
        }
      }

      // Ensure streaming is marked as done
      setMessages(prev => prev.map(m =>
        m.id === assistantId && m.isStreaming
          ? { ...m, isStreaming: false }
          : m
      ));

    } catch (error) {
      if (error instanceof Error && error.name === 'AbortError') {
        setMessages(prev => prev.map(m =>
          m.id === assistantId
            ? { ...m, isStreaming: false }
            : m
        ));
        return;
      }

      console.error('Error sending message:', error);
      const typedError = error instanceof Error ? error : new Error(String(error));
      setError(typedError);
      setMessages(prev => prev.map(m =>
        m.id === assistantId
          ? {
              ...m,
              content: 'Não consegui conectar ao servidor.',
              isStreaming: false,
              isError: true,
              errorType: 'unknown' as const,
            }
          : m
      ));
    } finally {
      setIsLoading(false);
      abortControllerRef.current = null;
    }
  }, [api, sessionId, input, isLoading, headers, body, onToolExecuted]);

  // Handle confirmation response
  const handleConfirm = useCallback(async (confirmId: string, confirmed: boolean) => {
    const pending = pendingConfirmsRef.current.get(confirmId);
    if (pending) {
      pending.resolve(confirmed);
      pendingConfirmsRef.current.delete(confirmId);
    }
  }, []);

  const clearMessages = useCallback(() => {
    abortControllerRef.current?.abort();
    abortControllerRef.current = null;
    setMessages([]);
    setInput('');
    setIsLoading(false);
    setError(null);
    if (persist && typeof window !== 'undefined') {
      try {
        localStorage.removeItem(storageKeyRef);
      } catch {}
    }
  }, [storageKeyRef, persist]);

  // Session management functions
  const loadSessions = useCallback(async () => {
    if (!sessionManagement || sessionManagement.level === 'none') return;
    setSessionsLoading(true);
    try {
      const res = await fetch('/api/chat/sessions', { credentials: 'include' });
      const data = await res.json();
      // jsonSuccess wraps in { data: {...} }, not { success, data }
      const sessionsData = data.data?.sessions || data.sessions;
      if (Array.isArray(sessionsData)) {
        setSessions(sessionsData);
      }
    } catch (e) {
      console.error('Failed to load sessions:', e);
    } finally {
      setSessionsLoading(false);
    }
  }, [sessionManagement]);

  const deleteSession = useCallback(async (targetSessionId: string) => {
    try {
      const res = await fetch(`/api/chat/sessions?sessionId=${encodeURIComponent(targetSessionId)}`, { method: 'DELETE', credentials: 'include' });
      const data = await res.json();
      if (data.data?.deleted || res.ok) {
        setSessions(prev => prev.filter(s => s.id !== targetSessionId));
        if (targetSessionId === sessionId) {
          setSessionId(crypto.randomUUID());
          clearMessages();
        }
      }
    } catch (e) {
      console.error('Failed to delete session:', e);
    }
  }, [sessionId, clearMessages]);

  const switchSession = useCallback(async (targetSessionId: string) => {
    setShowSessions(false);
    clearMessages();
    setSessionId(targetSessionId);
    setContextUsage(null);

    // Load existing messages for the session
    try {
      const res = await fetch(`/api/chat/sessions/${encodeURIComponent(targetSessionId)}/messages`, { credentials: 'include' });
      if (res.ok) {
        const data = await res.json();
        const msgs = data.data?.messages || data.messages;
        if (Array.isArray(msgs) && msgs.length > 0) {
          setMessages(msgs.map((m: Record<string, unknown>) => ({
            id: (m.id as string) || generateId(),
            role: (m.role as 'user' | 'assistant') || 'user',
            content: (m.content as string) || '',
            ...(m.toolCalls ? { toolCalls: m.toolCalls } : {}),
            ...(m.toolResults ? { toolResults: m.toolResults } : {}),
            ...(m.confirmation ? { confirmation: m.confirmation } : {}),
          })) as unknown as AgentChatMessage[]);

          // Estimate context usage from restored messages (~4 chars per token)
          const totalChars = msgs.reduce((sum: number, m: Record<string, unknown>) => {
            const content = (m.content as string) || '';
            return sum + content.length;
          }, 0);
          const estimatedTokens = Math.ceil(totalChars / 4);
          const maxTokens = 137000;
          setContextUsage({
            tokens: estimatedTokens,
            maxTokens,
            messageCount: msgs.length,
            usagePercent: Math.min(Math.round((estimatedTokens / maxTokens) * 100), 100),
          });
        }
      }
    } catch (e) {
      console.error('Failed to load session messages:', e);
    }
  }, [clearMessages, setMessages, setContextUsage]);

  return {
    messages,
    input,
    setInput,
    isLoading,
    error,
    sendMessage,
    stop: () => abortControllerRef.current?.abort(),
    setMessages: setMessages as any,
    clearMessages,
    handleInputChange: (e) => {
      setInput(e.target.value);
    },
    handleSubmit: (e: React.FormEvent) => {
      e.preventDefault();
      sendMessage();
    },
    handleConfirm,
    sessionId,
    setSessionId,
    contextUsage,
    setContextUsage,
    sessions,
    showSessions,
    setShowSessions,
    sessionsLoading,
    loadSessions,
    deleteSession,
    switchSession,
  };
}
