/**
 * @guilherme/agent-sdk/react/useCompletion
 *
 * Hook for text completion with streaming support.
 */

import { useState, useCallback, useRef } from 'react';

export interface UseCompletionOptions {
  /** API endpoint (default: '/api/completion') */
  api?: string;
  /** Initial completion value */
  initialCompletion?: string;
  /** Initial input value */
  initialInput?: string;
  /** Custom headers */
  headers?: Record<string, string>;
  /** Custom body fields */
  body?: Record<string, any>;
  /** Callback when completion finishes */
  onFinish?: (prompt: string, completion: string) => void;
  /** Callback on error */
  onError?: (error: Error) => void;
}

export interface UseCompletionReturn {
  /** Current completion text */
  completion: string;
  /** Set completion directly */
  setCompletion: (value: string) => void;
  /** Current input value */
  input: string;
  /** Set input directly */
  setInput: (value: string) => void;
  /** Whether a request is in progress */
  isLoading: boolean;
  /** Current error */
  error: Error | null;
  /** Trigger completion manually */
  complete: (prompt: string) => Promise<string>;
  /** Stop current streaming */
  stop: () => void;
  /** Handle input change (for form integration) */
  handleInputChange: (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => void;
  /** Handle form submit (for form integration) */
  handleSubmit: (e: React.FormEvent) => void;
}

/**
 * Hook for text completion with streaming support
 *
 * @example
 * ```tsx
 * function Completion() {
 *   const {
 *     completion,
 *     input,
 *     handleInputChange,
 *     handleSubmit,
 *     isLoading,
 *   } = useCompletion({ api: '/api/completion' });
 *
 *   return (
 *     <div>
 *       <form onSubmit={handleSubmit}>
 *         <input value={input} onChange={handleInputChange} />
 *         <button type="submit" disabled={isLoading}>Complete</button>
 *       </form>
 *       <div>{completion}</div>
 *     </div>
 *   );
 * }
 * ```
 */
export function useCompletion(options: UseCompletionOptions = {}): UseCompletionReturn {
  const {
    api = '/api/completion',
    initialCompletion = '',
    initialInput = '',
    headers,
    body,
    onFinish,
    onError,
  } = options;

  const [completion, setCompletion] = useState(initialCompletion);
  const [input, setInput] = useState(initialInput);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<Error | null>(null);

  const abortControllerRef = useRef<AbortController | null>(null);

  const complete = useCallback(async (prompt: string): Promise<string> => {
    if (!prompt.trim() || isLoading) return completion;

    setIsLoading(true);
    setError(null);
    setCompletion('');

    abortControllerRef.current = new AbortController();

    try {
      const response = await fetch(api, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          ...headers,
        },
        body: JSON.stringify({
          prompt,
          ...body,
        }),
        signal: abortControllerRef.current.signal,
      });

      if (!response.ok) {
        throw new Error(`API Error: ${response.status}`);
      }

      const reader = response.body!.getReader();
      const decoder = new TextDecoder();
      let buffer = '';
      let fullCompletion = '';

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop() ?? '';

        for (const line of lines) {
          if (!line.startsWith('data: ')) continue;
          const data = JSON.parse(line.slice(6));

          if (data.type === 'token') {
            fullCompletion += data.content;
            setCompletion(fullCompletion);
          } else if (data.type === 'done') {
            onFinish?.(prompt, fullCompletion);
          } else if (data.type === 'error') {
            throw new Error(data.error);
          }
        }
      }

      return fullCompletion;
    } catch (err) {
      if (err instanceof Error && err.name === 'AbortError') {
        return completion;
      }
      const error = err instanceof Error ? err : new Error(String(err));
      setError(error);
      onError?.(error);
      return '';
    } finally {
      setIsLoading(false);
      abortControllerRef.current = null;
    }
  }, [api, isLoading, headers, body, completion, onFinish, onError]);

  const stop = useCallback(() => {
    abortControllerRef.current?.abort();
  }, []);

  const handleInputChange = useCallback((e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setInput(e.target.value);
  }, []);

  const handleSubmit = useCallback((e: React.FormEvent) => {
    e.preventDefault();
    complete(input);
  }, [complete, input]);

  return {
    completion,
    setCompletion,
    input,
    setInput,
    isLoading,
    error,
    complete,
    stop,
    handleInputChange,
    handleSubmit,
  };
}
