/**
 * AgentChat - Componente de chat drop-in para agents
 *
 * Design: "Cosmic Noir" - Dark sofisticado com glassmorphism
 * e animações fluidas.
 */

'use client';

import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { useAgentChat, type AgentChatMessage } from './hooks';

/**
 * Generate accent color variants from a base hex color.
 * Produces primary (base), secondary (darker), and tertiary (lighter) variants.
 */
function buildAccentVars(hex: string): Record<string, string> {
  const parse = (h: string): [number, number, number] => {
    const clean = h.replace('#', '');
    return [
      parseInt(clean.slice(0, 2), 16),
      parseInt(clean.slice(2, 4), 16),
      parseInt(clean.slice(4, 6), 16),
    ];
  };
  const toHex = (r: number, g: number, b: number) =>
    '#' + [r, g, b].map((c) => Math.max(0, Math.min(255, Math.round(c))).toString(16).padStart(2, '0')).join('');

  const [r, g, b] = parse(hex);
  // Secondary: slightly darker
  const secondary = toHex(r * 0.8, g * 0.8, b * 0.8);
  // Tertiary: slightly lighter
  const tertiary = toHex(r + (255 - r) * 0.25, g + (255 - g) * 0.25, b + (255 - b) * 0.25);

  return {
    '--accent-primary': hex,
    '--accent-secondary': secondary,
    '--accent-tertiary': tertiary,
    '--accent-r': String(r),
    '--accent-g': String(g),
    '--accent-b': String(b),
  };
}

export interface AgentChatProps {
  endpoint: string;
  title?: string;
  subtitle?: string;
  theme?: 'dark' | 'light';
  examples?: string[];
  toolLabels?: Record<string, string>;
  onToolExecuted?: () => void;
  sessionId?: string;
  /** Custom icon rendered in the FAB button and header avatar. Falls back to default sparkles. */
  icon?: React.ReactNode;
  /** Custom accent color (hex, e.g. '#6366f1'). Overrides the default purple accent. */
  accentColor?: string;
  /** Predefined quick prompts rendered as clickable pills above the input. */
  quickPrompts?: { label: string; prompt: string; icon?: string }[];
  labels?: {
    placeholder?: string;
    processing?: string;
    newMessage?: string;
    clearHistory?: string;
    retry?: string;
    confirm?: string;
    cancel?: string;
  };
  /** Session management configuration */
  sessionManagement?: {
    level: 'none' | 'basic' | 'full';
    maxSessions?: number;
    persistDays?: number;
  };
}

export function AgentChat({
  endpoint,
  title = 'Assistente',
  subtitle = 'AI powered',
  theme = 'dark',
  examples,
  toolLabels = {},
  onToolExecuted,
  sessionId: propSessionId,
  labels = {},
  icon,
  accentColor,
  quickPrompts,
  sessionManagement,
}: AgentChatProps) {
  const [sessionResetVersion, setSessionResetVersion] = useState(0);
  const [isOpen, setIsOpen] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const effectiveSessionId = propSessionId
    ? `${propSessionId}::${sessionResetVersion}`
    : undefined;

  useEffect(() => {
    setSessionResetVersion(0);
  }, [propSessionId]);

  return (
    <AgentChatSession
      key={effectiveSessionId ?? `agent-chat-session-${sessionResetVersion}`}
      endpoint={endpoint}
      title={title}
      subtitle={subtitle}
      theme={theme}
      examples={examples}
      toolLabels={toolLabels}
      onToolExecuted={onToolExecuted}
      sessionId={effectiveSessionId}
      labels={labels}
      icon={icon}
      accentColor={accentColor}
      quickPrompts={quickPrompts}
      sessionManagement={sessionManagement}
      isOpen={isOpen}
      isMinimized={isMinimized}
      setIsOpen={setIsOpen}
      setIsMinimized={setIsMinimized}
      onResetSession={() => setSessionResetVersion((current) => current + 1)}
    />
  );
}

interface AgentChatSessionProps extends AgentChatProps {
  isOpen: boolean;
  isMinimized: boolean;
  setIsOpen: React.Dispatch<React.SetStateAction<boolean>>;
  setIsMinimized: React.Dispatch<React.SetStateAction<boolean>>;
  onResetSession?: () => void;
}

function AgentChatSession({
  endpoint,
  title = 'Assistente',
  subtitle = 'AI powered',
  theme = 'dark',
  examples,
  toolLabels = {},
  onToolExecuted,
  sessionId: propSessionId,
  labels = {},
  icon,
  accentColor,
  quickPrompts,
  sessionManagement,
  isOpen,
  isMinimized,
  setIsOpen,
  setIsMinimized,
  onResetSession,
}: AgentChatSessionProps) {
  const chat = useAgentChat({
    api: endpoint,
    sessionId: propSessionId,
    onToolExecuted,
    storageKey: 'agent-chat',
    persist: true,
    sessionManagement,
  });

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const messagesContainerRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLTextAreaElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const shouldAutoScroll = useRef(true);
  const [showScrollBtn, setShowScrollBtn] = useState(false);
  const [size, setSize] = useState({ width: 420, height: 580 });
  const isResizing = useRef(false);

  const accentStyle = useMemo(
    () => accentColor ? buildAccentVars(accentColor) as React.CSSProperties : undefined,
    [accentColor]
  );

  const scrollToBottom = useCallback((behavior: ScrollBehavior = 'smooth') => {
    messagesEndRef.current?.scrollIntoView({ behavior, block: 'end' });
  }, []);

  useEffect(() => {
    if (isOpen && !isMinimized) {
      requestAnimationFrame(() => scrollToBottom('instant'));
      setTimeout(() => inputRef.current?.focus(), 100);
    }
  }, [isOpen, isMinimized, scrollToBottom]);

  useEffect(() => {
    if (shouldAutoScroll.current) {
      scrollToBottom('smooth');
    }
  }, [chat.messages, scrollToBottom]);

  const handleContainerScroll = (e: React.UIEvent<HTMLDivElement>) => {
    const el = e.currentTarget;
    const distFromBottom = el.scrollHeight - el.scrollTop - el.clientHeight;
    const atBottom = distFromBottom < 80;
    shouldAutoScroll.current = atBottom;
    if (!atBottom && !showScrollBtn) setShowScrollBtn(true);
    if (atBottom && showScrollBtn) setShowScrollBtn(false);
  };

  const handleSend = () => {
    if (!chat.input.trim() || chat.isLoading) return;
    chat.sendMessage();
    // Reset textarea height
    const el = inputRef.current;
    if (el) {
      el.style.height = 'auto';
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleResizeStart = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
    isResizing.current = true;
    const startX = e.clientX;
    const startY = e.clientY;
    const startWidth = containerRef.current?.offsetWidth ?? 420;
    const startHeight = containerRef.current?.offsetHeight ?? 580;

    const onMouseMove = (ev: MouseEvent) => {
      if (!isResizing.current) return;
      const dx = startX - ev.clientX;
      const dy = startY - ev.clientY;
      setSize({
        width: Math.min(Math.max(startWidth + dx, 320), window.innerWidth * 0.9),
        height: Math.min(Math.max(startHeight + dy, 400), window.innerHeight * 0.85),
      });
    };

    const onMouseUp = () => {
      isResizing.current = false;
      document.removeEventListener('mousemove', onMouseMove);
      document.removeEventListener('mouseup', onMouseUp);
      document.body.style.userSelect = '';
      document.body.style.cursor = '';
    };

    document.body.style.userSelect = 'none';
    document.body.style.cursor = 'nwse-resize';
    document.addEventListener('mousemove', onMouseMove);
    document.addEventListener('mouseup', onMouseUp);
  }, []);

  // Floating Button (closed state)
  if (!isOpen) {
    const fabAccentVars = accentColor
      ? `.agent-chat-fab, .agent-chat-pulse .pulse-dot { --accent-primary: ${accentColor}; --accent-secondary: ${buildAccentVars(accentColor)['--accent-secondary']}; --accent-tertiary: ${buildAccentVars(accentColor)['--accent-tertiary']}; --accent-r: ${buildAccentVars(accentColor)['--accent-r']}; --accent-g: ${buildAccentVars(accentColor)['--accent-g']}; --accent-b: ${buildAccentVars(accentColor)['--accent-b']}; }`
      : '';
    return (
      <>
        {fabAccentVars && <style>{fabAccentVars}</style>}
        <button
          onClick={() => setIsOpen(true)}
          className="agent-chat-fab"
          title="Abrir assistente"
          aria-label="Abrir assistente"
        >
          {icon || <MessageIcon />}
          <span className="fab-label">Chat</span>
          <div className="fab-ripple" />
        </button>
        {chat.isLoading && (
          <div className="agent-chat-pulse">
            <div className="pulse-dot" />
          </div>
        )}
        <style>{fabStyles}</style>
      </>
    );
  }

  // Chat Modal
  return (
    <div
      ref={containerRef}
      className={`agent-chat-container ${theme} ${isMinimized ? 'minimized' : ''}`}
      style={{ width: size.width, height: isMinimized ? undefined : size.height, ...accentStyle }}
    >
      {/* Resize Grip - Top Left */}
      {!isMinimized && (
        <div className="resize-grip" onMouseDown={handleResizeStart} />
      )}
      {/* Header */}
      <header className="agent-chat-header">
        <div className="header-left">
          <div className="avatar">
            {icon || <SparklesIcon />}
            <div className="avatar-glow" />
          </div>
          <div className="header-text">
            <h3>{title}</h3>
            <p>{subtitle}</p>
          </div>
        </div>
        <div className="header-actions">
          {/* Session management button */}
          {sessionManagement && sessionManagement.level !== 'none' && (
            <button
              className="session-list-btn"
              onClick={() => { chat.loadSessions(); chat.setShowSessions(!chat.showSessions); }}
              title="Sessoes"
            >
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="12" cy="12" r="10" />
                <polyline points="12 6 12 12 16 14" />
              </svg>
            </button>
          )}
          <button
            onClick={() => {
              chat.clearMessages();
              onResetSession?.();
            }}
            className="icon-btn"
            title={labels.clearHistory || 'Limpar histórico'}
            aria-label={labels.clearHistory || 'Limpar histórico'}
          >
            <TrashIcon />
          </button>
          <button
            onClick={() => setIsMinimized(!isMinimized)}
            className="icon-btn"
            title={isMinimized ? 'Expandir' : 'Minimizar'}
            aria-label={isMinimized ? 'Expandir' : 'Minimizar'}
          >
            {isMinimized ? <ExpandIcon /> : <MinimizeIcon />}
          </button>
          <button
            onClick={() => setIsOpen(false)}
            className="icon-btn close"
            title="Fechar"
            aria-label="Fechar"
          >
            <CloseIcon />
          </button>
        </div>
      </header>

      {/* Sessions drawer */}
      {chat.showSessions && sessionManagement && sessionManagement.level !== 'none' && (
        <div className="session-drawer-overlay" onClick={() => chat.setShowSessions(false)}>
          <div className="session-drawer" onClick={e => e.stopPropagation()}>
            <div className="session-drawer-header">
              <h3>Sessoes</h3>
              <button className="session-drawer-close" onClick={() => chat.setShowSessions(false)}>x</button>
            </div>
            <div className="session-drawer-list">
              {chat.sessionsLoading ? (
                <div className="session-drawer-empty">Carregando...</div>
              ) : chat.sessions.length === 0 ? (
                <div className="session-drawer-empty">Nenhuma sessao</div>
              ) : (
                chat.sessions.map(session => (
                  <div
                    key={session.id}
                    className={`session-drawer-item ${session.id === chat.sessionId ? 'active' : ''}`}
                    onClick={() => chat.switchSession(session.id)}
                  >
                    <div className="session-drawer-item-title">{session.title || 'Nova conversa'}</div>
                    <div className="session-drawer-item-meta">
                      {session.messageCount} msgs · {new Date(session.updatedAt).toLocaleDateString('pt-BR')}
                    </div>
                    {(sessionManagement.level === 'basic' || sessionManagement.level === 'full') && (
                      <button
                        className="session-drawer-item-delete"
                        onClick={(e) => { e.stopPropagation(); chat.deleteSession(session.id); }}
                        title="Apagar sessao"
                      >
                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                          <line x1="18" y1="6" x2="6" y2="18" />
                          <line x1="6" y1="6" x2="18" y2="18" />
                        </svg>
                      </button>
                    )}
                  </div>
                ))
              )}
            </div>
            <button
              className="session-drawer-new"
              onClick={() => { chat.setSessionId(crypto.randomUUID()); chat.clearMessages(); chat.setShowSessions(false); }}
            >
              + Nova conversa
            </button>
          </div>
        </div>
      )}

      {/* Context usage bar */}
      {chat.contextUsage && chat.contextUsage.messageCount > 4 && (
        <div className="context-usage-bar">
          <div className="context-usage-info">
            <div 
              className={`context-usage-fill ${chat.contextUsage.usagePercent > 80 ? 'critical' : chat.contextUsage.usagePercent > 50 ? 'warning' : 'normal'}`}
              style={{ width: `${Math.min(chat.contextUsage.usagePercent, 100)}%` }}
            />
          </div>
          <span className="context-usage-text">
            {chat.contextUsage.messageCount} msgs · {Math.round(chat.contextUsage.tokens / 1000)}k tokens
          </span>
          {chat.contextUsage.usagePercent > 60 && (
            <button
              className="context-compact-btn"
              onClick={async () => {
                try {
                  const res = await fetch('/api/chat/compact', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ sessionId: chat.sessionId, keepLast: 12 }),
                    credentials: 'include',
                  });
                  const data = await res.json();
                  if (data.data?.compacted) {
                    chat.setContextUsage(prev => prev ? {
                      ...prev,
                      tokens: prev.tokens * 0.3,
                      messageCount: data.data.after,
                      usagePercent: Math.round((prev.tokens * 0.3 / prev.maxTokens) * 100),
                    } : null);
                  }
                } catch (e) {
                  console.error('Compact failed:', e);
                }
              }}
              title="Compactar contexto (manter últimas 12 mensagens)"
            >
              Compactar
            </button>
          )}
        </div>
      )}

      {/* Messages */}
      {!isMinimized && (
        <div
          ref={messagesContainerRef}
          className="agent-chat-messages"
          onScroll={handleContainerScroll}
        >
          {chat.messages.length === 0 && examples && (
            <div className="examples-panel">
              <div className="examples-header">
                <LightbulbIcon />
                <span>Experimente perguntar</span>
              </div>
              <ul>
                {examples.map((ex, i) => (
                  <li
                    key={i}
                    onClick={() => {
                      chat.setInput(ex);
                      inputRef.current?.focus();
                    }}
                  >
                    {ex}
                  </li>
                ))}
              </ul>
            </div>
          )}

          {chat.messages.map((msg, idx) => (
            <MessageBubble
              key={msg.id || idx}
              message={msg}
              toolLabels={toolLabels}
              labels={labels}
              onConfirm={chat.handleConfirm}
            />
          ))}

          {/* Loading indicator */}
          {chat.isLoading && chat.messages[chat.messages.length - 1]?.isStreaming && !chat.messages[chat.messages.length - 1]?.content && !chat.messages[chat.messages.length - 1]?.statusSteps?.length && (
            <div className="message-wrapper assistant">
              <div className="message-bubble loading">
                <div className="typing-indicator">
                  <span /><span /><span />
                </div>
                <span className="loading-text">{labels.processing || 'Pensando...'}</span>
              </div>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>
      )}

      {/* Scroll to bottom button - outside scroll container */}
      {showScrollBtn && !isMinimized && (
        <button
          onClick={() => {
            shouldAutoScroll.current = true;
            setShowScrollBtn(false);
            scrollToBottom('smooth');
          }}
          className="scroll-to-bottom"
          aria-label="Rolar para baixo"
        >
          <ArrowDownIcon />
          <span className="scroll-to-bottom-label">Baixo</span>
        </button>
      )}

      {/* Input */}
      {!isMinimized && (
        <footer className="agent-chat-input">
          {quickPrompts && quickPrompts.length > 0 && (
            <div className="quick-prompts-bar">
              {quickPrompts.map((qp, i) => (
                <button
                  key={i}
                  className="quick-prompt-pill"
                  onClick={() => {
                    const current = chat.input.trim();
                    const newText = current ? `${current} ${qp.prompt}` : qp.prompt;
                    chat.setInput(newText);
                    inputRef.current?.focus();
                  }}
                  title={qp.prompt}
                >
                  {qp.icon && <span className="quick-prompt-icon">{qp.icon}</span>}
                  {qp.label}
                </button>
              ))}
            </div>
          )}
          <div className="input-wrapper">
            <textarea
              ref={inputRef}
              value={chat.input}
              onChange={(e) => {
                chat.handleInputChange(e);
                // Auto-resize
                const el = e.target;
                el.style.height = 'auto';
                el.style.height = Math.min(el.scrollHeight, 120) + 'px';
              }}
              onKeyDown={handleKeyPress}
              placeholder={
                chat.isLoading
                  ? labels.processing || 'Aguardando resposta...'
                  : labels.placeholder || 'Digite sua mensagem...'
              }
              disabled={chat.isLoading}
              rows={1}
              style={{ resize: 'none', overflow: 'hidden' }}
            />
            {chat.isLoading ? (
              <button
                onClick={chat.stop}
                className="send-btn stop"
                aria-label="Parar geração"
              >
                <StopIcon />
              </button>
            ) : (
              <button
                onClick={handleSend}
                disabled={!chat.input.trim()}
                className="send-btn"
                aria-label="Enviar mensagem"
              >
                <SendIcon />
              </button>
            )}
          </div>
          <div className="input-glow" />
        </footer>
      )}

      <style>{chatStyles}</style>
    </div>
  );
}

// ========================================
// Markdown Renderer (zero dependencies)
// ========================================

function MarkdownRenderer({ content }: { content: string }) {
  const blocks = parseMarkdownBlocks(content);

  return (
    <div className="md-content">
      {blocks.map((block, i) => (
        <MarkdownBlock key={i} block={block} />
      ))}
    </div>
  );
}

type Block =
  | { type: 'heading'; level: number; text: string }
  | { type: 'code'; lang: string; code: string }
  | { type: 'blockquote'; text: string }
  | { type: 'ul'; items: string[] }
  | { type: 'ol'; items: string[] }
  | { type: 'hr' }
  | { type: 'paragraph'; text: string };

function parseMarkdownBlocks(content: string): Block[] {
  const blocks: Block[] = [];
  const lines = content.split('\n');
  let i = 0;

  while (i < lines.length) {
    const line = lines[i];

    // Empty line
    if (line.trim() === '') {
      i++;
      continue;
    }

    // Code block
    if (line.trimStart().startsWith('```')) {
      const lang = line.trimStart().slice(3).trim();
      const codeLines: string[] = [];
      i++;
      while (i < lines.length && !lines[i].trimStart().startsWith('```')) {
        codeLines.push(lines[i]);
        i++;
      }
      i++; // skip closing ```
      blocks.push({ type: 'code', lang, code: codeLines.join('\n') });
      continue;
    }

    // Heading
    const headingMatch = line.match(/^(#{1,6})\s+(.+)/);
    if (headingMatch) {
      blocks.push({
        type: 'heading',
        level: headingMatch[1].length,
        text: headingMatch[2],
      });
      i++;
      continue;
    }

    // Horizontal rule
    if (/^(-{3,}|\*{3,}|_{3,})\s*$/.test(line.trim())) {
      blocks.push({ type: 'hr' });
      i++;
      continue;
    }

    // Blockquote
    if (line.trimStart().startsWith('>')) {
      const quoteLines: string[] = [];
      while (i < lines.length && (lines[i].trimStart().startsWith('>') || (lines[i].trim() !== '' && quoteLines.length > 0 && !lines[i].trimStart().startsWith('#') && !lines[i].trimStart().startsWith('```')))) {
        quoteLines.push(lines[i].replace(/^>\s?/, ''));
        i++;
      }
      blocks.push({ type: 'blockquote', text: quoteLines.join('\n') });
      continue;
    }

    // Unordered list
    if (/^[\s]*[-*+]\s+/.test(line)) {
      const items: string[] = [];
      while (i < lines.length && /^[\s]*[-*+]\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^[\s]*[-*+]\s+/, ''));
        i++;
      }
      blocks.push({ type: 'ul', items });
      continue;
    }

    // Ordered list
    if (/^[\s]*\d+\.\s+/.test(line)) {
      const items: string[] = [];
      while (i < lines.length && /^[\s]*\d+\.\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^[\s]*\d+\.\s+/, ''));
        i++;
      }
      blocks.push({ type: 'ol', items });
      continue;
    }

    // Paragraph (collect consecutive non-empty lines)
    const paraLines: string[] = [];
    while (
      i < lines.length &&
      lines[i].trim() !== '' &&
      !lines[i].trimStart().startsWith('#') &&
      !lines[i].trimStart().startsWith('```') &&
      !lines[i].trimStart().startsWith('>') &&
      !/^[\s]*[-*+]\s+/.test(lines[i]) &&
      !/^[\s]*\d+\.\s+/.test(lines[i]) &&
      !/^(-{3,}|\*{3,}|_{3,})\s*$/.test(lines[i].trim())
    ) {
      paraLines.push(lines[i]);
      i++;
    }
    if (paraLines.length > 0) {
      blocks.push({ type: 'paragraph', text: paraLines.join('\n') });
    }
  }

  return blocks;
}

function MarkdownBlock({ block }: { block: Block }) {
  switch (block.type) {
    case 'heading': {
      const Tag = `h${Math.min(block.level, 6)}` as 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6';
      return <Tag className={`md-heading md-h${block.level}`}>{renderInline(block.text)}</Tag>;
    }
    case 'code':
      return (
        <div className="md-code-block">
          {block.lang && <div className="md-code-lang">{block.lang}</div>}
          <pre><code>{block.code}</code></pre>
        </div>
      );
    case 'blockquote':
      return <blockquote className="md-blockquote">{renderInline(block.text)}</blockquote>;
    case 'ul':
      return (
        <ul className="md-list">
          {block.items.map((item, i) => <li key={i}>{renderInline(item)}</li>)}
        </ul>
      );
    case 'ol':
      return (
        <ol className="md-list">
          {block.items.map((item, i) => <li key={i}>{renderInline(item)}</li>)}
        </ol>
      );
    case 'hr':
      return <hr className="md-hr" />;
    case 'paragraph':
      return <p className="md-paragraph">{renderInline(block.text)}</p>;
  }
}

function renderInline(text: string): React.ReactNode[] {
  const nodes: React.ReactNode[] = [];
  // Tokenize: code, bold, italic, links, then plain text
  const inlineRegex = /(`[^`]+`)|(\*\*[^*]+\*\*)|(\*[^*]+\*)|(\[[^\]]+\]\([^)]+\))/g;
  let lastIndex = 0;
  let match;
  let key = 0;

  while ((match = inlineRegex.exec(text)) !== null) {
    // Plain text before this match
    if (match.index > lastIndex) {
      nodes.push(text.slice(lastIndex, match.index));
    }

    const [full] = match;

    if (full.startsWith('`')) {
      // Inline code
      nodes.push(<code key={key++} className="md-inline-code">{full.slice(1, -1)}</code>);
    } else if (full.startsWith('**')) {
      // Bold
      nodes.push(<strong key={key++}>{full.slice(2, -2)}</strong>);
    } else if (full.startsWith('*')) {
      // Italic
      nodes.push(<em key={key++}>{full.slice(1, -1)}</em>);
    } else if (full.startsWith('[')) {
      // Link
      const linkMatch = full.match(/\[([^\]]+)\]\(([^)]+)\)/);
      if (linkMatch) {
        nodes.push(
          <a key={key++} href={linkMatch[2]} target="_blank" rel="noopener noreferrer" className="md-link">
            {linkMatch[1]}
          </a>
        );
      } else {
        nodes.push(full);
      }
    }

    lastIndex = match.index + full.length;
  }

  // Remaining plain text
  if (lastIndex < text.length) {
    nodes.push(text.slice(lastIndex));
  }

  return nodes;
}

// ========================================
// MessageBubble Component
// ========================================
function MessageBubble({
  message,
  toolLabels,
  labels,
  onConfirm,
}: {
  message: AgentChatMessage;
  toolLabels: Record<string, string>;
  labels: any;
  onConfirm: (confirmId: string, confirmed: boolean) => void;
}) {
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    const text = message.content || '';
    if (!text) return;
    try {
      await navigator.clipboard.writeText(text);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      // Fallback
      const textarea = document.createElement('textarea');
      textarea.value = text;
      document.body.appendChild(textarea);
      textarea.select();
      document.execCommand('copy');
      document.body.removeChild(textarea);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  if (message.isStreaming && !message.content && !message.statusSteps?.length && !message.pendingConfirm) {
    return null;
  }

  const isUser = message.role === 'user';
  const isError = message.isError;

  const renderToolCallSummary = (toolCalls: any[]) => (
    <div className="tool-calls">
      {toolCalls.map((call, idx) => {
        const label = toolLabels[call.function?.name] || call.function?.name || call.name || 'tool';
        let detail = '';
        try {
          const args = typeof call.function?.arguments === 'string'
            ? JSON.parse(call.function.arguments)
            : call.function?.arguments || call.args;
          if (args.date) {
            const [, m, d] = args.date.split('-');
            detail = ` · ${d}/${m}`;
          } else if (args.month) {
            const [y, mo] = args.month.split('-');
            detail = ` · ${mo}/${y}`;
          } else if (args.phone) {
            detail = ` · ***${args.phone.slice(-4)}`;
          }
        } catch {}

        return (
          <span key={idx} className="tool-badge">
            <CheckIcon size={12} />
            {label}{detail}
          </span>
        );
      })}
    </div>
  );

  const renderContent = (content: string, streaming: boolean) => {
    const displayContent = streaming && content ? content + '▌' : content;
    return <MarkdownRenderer content={displayContent} />;
  };

  return (
    <div className={`message-wrapper ${isUser ? 'user' : 'assistant'} ${isError ? 'error' : ''}`}>
      <div className={`message-bubble ${isUser ? 'user' : 'assistant'} ${isError ? 'error' : ''}`}>
        {/* Status steps */}
        {message.isStreaming && !message.pendingConfirm && message.statusSteps && message.statusSteps.length > 0 && (
          <div className="status-steps">
            {message.statusSteps.map((step, i) => (
              <React.Fragment key={i}>
                {i > 0 && <span className="step-separator">/</span>}
                <div className={`status-step ${i === message.statusSteps!.length - 1 ? 'active' : 'completed'}`}>
                  {i === message.statusSteps!.length - 1 ? (
                    <div className="spinner" />
                  ) : (
                    <CheckIcon size={10} />
                  )}
                  <span>{step}</span>
                </div>
              </React.Fragment>
            ))}
          </div>
        )}

        {/* Tool calls summary */}
        {!message.isStreaming && message.toolCalls && message.toolCalls.length > 0 && (
          renderToolCallSummary(message.toolCalls)
        )}

        {/* Content */}
        {(message.content || (!message.isStreaming && !message.pendingConfirm)) && (
          <div className={`message-body ${isUser ? 'user' : ''} ${isError ? 'error' : ''}`}>
            {isError && (
              <div className="error-header">
                <AlertIcon size={14} />
                <span>Erro</span>
              </div>
            )}
            {isError || isUser ? (
              <p>{message.content}</p>
            ) : (
              renderContent(message.content, message.isStreaming || false)
            )}
          </div>
        )}

        {/* Copy button - assistant messages only, after streaming */}
        {!isUser && !message.isStreaming && message.content && (
          <button
            onClick={handleCopy}
            className={`copy-btn ${copied ? 'copied' : ''}`}
            title={copied ? 'Copiado!' : 'Copiar mensagem'}
            aria-label={copied ? 'Copiado!' : 'Copiar mensagem'}
          >
            {copied ? <CheckMarkIcon size={12} /> : <CopyIcon size={12} />}
            <span>{copied ? 'Copiado' : 'Copiar'}</span>
          </button>
        )}

        {/* Confirmation dialog */}
        {message.pendingConfirm && (
          <div className="confirm-dialog">
            <div className="confirm-message">
              <AlertIcon size={18} />
              <p>{message.pendingConfirm.message}</p>
            </div>
            <div className="confirm-actions">
              <button
                onClick={() => onConfirm(message.pendingConfirm!.confirmId, true)}
                className="confirm-btn danger"
              >
                {labels.confirm || 'Confirmar'}
              </button>
              <button
                onClick={() => onConfirm(message.pendingConfirm!.confirmId, false)}
                className="confirm-btn secondary"
              >
                {labels.cancel || 'Cancelar'}
              </button>
            </div>
          </div>
        )}

        {/* Retry button */}
        {isError && message.errorType === 'api' && (
          <button className="retry-btn">
            <RotateCcwIcon size={12} />
            {labels.retry || 'Tentar novamente'}
          </button>
        )}
      </div>
    </div>
  );
}

