'use client';

/**
 * AgentBuilder - UI para criar e configurar agents
 *
 * Design: "Cosmic Noir" - Dark sofisticado com glassmorphism
 */

import { useState, useCallback } from 'react';

// Types
export interface BuilderAgentConfig {
  name: string;
  systemPrompt: string;
  provider: {
    type: 'openai' | 'anthropic' | 'zai' | 'groq' | 'custom';
    baseUrl: string;
    apiKey: string;
    model: string;
  };
  tools: BuilderToolConfig[];
  mcpServers: BuilderMcpServerConfig[];
  settings: {
    temperature: number;
    maxIterations: number;
    historySize: number;
  };
}

export interface BuilderToolConfig {
  id: string;
  name: string;
  description: string;
  parameters: any;
  code: string;
  awaitConfirm: boolean;
  confirmMessage: string;
}

export interface BuilderMcpServerConfig {
  id: string;
  name: string;
  command: string;
  args: string[];
  env: Record<string, string>;
  enabled: boolean;
}

export type AgentConfig = BuilderAgentConfig;
export type ToolConfig = BuilderToolConfig;
export type McpServerConfig = BuilderMcpServerConfig;

export interface AgentBuilderProps {
  initialConfig?: Partial<AgentConfig>;
  onExport?: (config: AgentConfig) => void;
  onSave?: (config: AgentConfig) => void;
  onTest?: (config: AgentConfig) => void;
  showPreview?: boolean;
}

// Provider presets
const PROVIDER_PRESETS = {
  openai: { type: 'openai' as const, baseUrl: 'https://api.openai.com/v1', model: 'gpt-4o-mini' },
  anthropic: { type: 'anthropic' as const, baseUrl: 'https://api.anthropic.com/v1', model: 'claude-3-5-sonnet-latest' },
  zai: { type: 'zai' as const, baseUrl: 'https://api.z.ai/api/paas/v4', model: 'glm-4-flash' },
  groq: { type: 'groq' as const, baseUrl: 'https://api.groq.com/openai/v1', model: 'llama-3.1-70b-versatile' },
  custom: { type: 'custom' as const, baseUrl: '', model: '' },
};

export function AgentBuilder({
  initialConfig,
  onExport,
  onSave,
  onTest,
}: AgentBuilderProps) {
  const [activeTab, setActiveTab] = useState<'prompt' | 'tools' | 'mcp' | 'settings'>('prompt');
  const [config, setConfig] = useState<AgentConfig>({
    name: initialConfig?.name || 'Meu Agent',
    systemPrompt: initialConfig?.systemPrompt || '',
    provider: initialConfig?.provider || {
      type: 'openai',
      baseUrl: 'https://api.openai.com/v1',
      apiKey: '',
      model: 'gpt-4o-mini',
    },
    tools: initialConfig?.tools || [],
    mcpServers: initialConfig?.mcpServers || [],
    settings: initialConfig?.settings || { temperature: 0.7, maxIterations: 6, historySize: 20 },
  });

  const [editingTool, setEditingTool] = useState<ToolConfig | null>(null);
  const [editingMcp, setEditingMcp] = useState<McpServerConfig | null>(null);
  const [testResult, setTestResult] = useState<{ status: 'idle' | 'loading' | 'success' | 'error'; message: string }>({ status: 'idle', message: '' });

  const updateConfig = useCallback((updates: Partial<AgentConfig>) => {
    setConfig(prev => ({ ...prev, ...updates }));
  }, []);

  const handleProviderTypeChange = (type: AgentConfig['provider']['type']) => {
    const preset = PROVIDER_PRESETS[type];
    updateConfig({ provider: { ...config.provider, ...preset, type } });
  };

  const addTool = () => {
    const newTool: ToolConfig = {
      id: crypto.randomUUID(),
      name: '',
      description: '',
      parameters: { type: 'object', properties: {}, required: [] },
      code: `async (args) => {\n  // Sua lógica aqui\n  return { success: true };\n}`,
      awaitConfirm: false,
      confirmMessage: '',
    };
    setEditingTool(newTool);
  };

  const saveTool = (tool: ToolConfig) => {
    if (!tool.name) return;
    setConfig(prev => {
      const exists = prev.tools.find(t => t.id === tool.id);
      if (exists) {
        return { ...prev, tools: prev.tools.map(t => t.id === tool.id ? tool : t) };
      }
      return { ...prev, tools: [...prev.tools, tool] };
    });
    setEditingTool(null);
  };

  const deleteTool = (id: string) => {
    setConfig(prev => ({ ...prev, tools: prev.tools.filter(t => t.id !== id) }));
  };

  const addMcpServer = () => {
    const newServer: McpServerConfig = {
      id: crypto.randomUUID(),
      name: 'Novo MCP Server',
      command: 'npx',
      args: ['-y', '@modelcontextprotocol/server-filesystem', './data'],
      env: {},
      enabled: true,
    };
    setEditingMcp(newServer);
  };

  const saveMcpServer = (server: McpServerConfig) => {
    if (!server.name) return;
    setConfig(prev => {
      const exists = prev.mcpServers.find(s => s.id === server.id);
      if (exists) {
        return { ...prev, mcpServers: prev.mcpServers.map(s => s.id === server.id ? server : s) };
      }
      return { ...prev, mcpServers: [...prev.mcpServers, server] };
    });
    setEditingMcp(null);
  };

  const deleteMcpServer = (id: string) => {
    setConfig(prev => ({ ...prev, mcpServers: prev.mcpServers.filter(s => s.id !== id) }));
  };

  const generateExportCode = (): string => {
    const toolsCode = config.tools.map(tool => `  defineTool({
    name: '${tool.name}',
    description: '${tool.description}',
    parameters: ${JSON.stringify(tool.parameters, null, 4)},
    execute: ${tool.code},
    awaitConfirm: ${tool.awaitConfirm},${tool.awaitConfirm ? `\n    confirmMessage: () => '${tool.confirmMessage}',` : ''}
  }),`).join('\n\n');

    const mcpCode = config.mcpServers.filter(s => s.enabled).map(server => `  // MCP: ${server.name}
  createMcpTools({
    command: '${server.command}',
    args: ${JSON.stringify(server.args)},
    env: ${JSON.stringify(server.env)},
    prefix: '${server.name.toLowerCase().replace(/\s+/g, '_')}_',
  }),`).join('\n\n');

    return `// Gerado por Agent Builder
import { createAgentRoute, defineTool } from '@guilherme/agent-sdk';
import { createMcpTools } from '@guilherme/agent-sdk/mcp';
import { z } from 'zod';

const tools = [
${toolsCode || '  // Adicione suas tools aqui'}
];

const mcpTools = await Promise.all([
${mcpCode || '  // Adicione MCP servers aqui'}
]);

export const POST = createAgentRoute({
  provider: {
    baseUrl: '${config.provider.baseUrl}',
    apiKey: process.env.AI_API_KEY!,
    model: '${config.provider.model}',
  },
  systemPrompt: \`${config.systemPrompt}\`,
  tools: [...tools, ...mcpTools.flat()],
  temperature: ${config.settings.temperature},
  maxIterations: ${config.settings.maxIterations},
  historySize: ${config.settings.historySize},
});
`;
  };

  const handleExport = () => {
    const code = generateExportCode();
    navigator.clipboard.writeText(code);
    onExport?.(config);
    setTestResult({ status: 'success', message: 'Código copiado!' });
    setTimeout(() => setTestResult({ status: 'idle', message: '' }), 2000);
  };

  const handleTest = async () => {
    if (!onTest) return;
    setTestResult({ status: 'loading', message: 'Testando...' });
    try {
      await onTest(config);
      setTestResult({ status: 'success', message: 'Agent funcionando!' });
    } catch (error) {
      setTestResult({ status: 'error', message: error instanceof Error ? error.message : 'Erro ao testar' });
    }
  };

  return (
    <div className="agent-builder-container">
      {/* Header */}
      <header className="builder-header">
        <div className="header-title">
          <div className="agent-icon">
            <BotIcon />
          </div>
          <input
            type="text"
            value={config.name}
            onChange={e => updateConfig({ name: e.target.value })}
            className="title-input"
            placeholder="Nome do Agent"
          />
        </div>
        <div className="header-actions">
          {testResult.status !== 'idle' && (
            <span className={`status-badge ${testResult.status}`}>
              {testResult.status === 'loading' && <SpinnerIcon />}
              {testResult.message}
            </span>
          )}
          {onTest && (
            <button onClick={handleTest} className="btn secondary">
              <PlayIcon /> Testar
            </button>
          )}
          <button onClick={handleExport} className="btn secondary">
            <CopyIcon /> Exportar
          </button>
          <button onClick={() => onSave?.(config)} className="btn primary">
            <SaveIcon /> Salvar
          </button>
        </div>
      </header>

      {/* Tabs */}
      <nav className="builder-tabs">
        {(['prompt', 'tools', 'mcp', 'settings'] as const).map(tab => (
          <button
            key={tab}
            className={`tab ${activeTab === tab ? 'active' : ''}`}
            onClick={() => setActiveTab(tab)}
          >
            {tab === 'prompt' && <FileTextIcon />}
            {tab === 'tools' && <WrenchIcon />}
            {tab === 'mcp' && <ServerIcon />}
            {tab === 'settings' && <SettingsIcon />}
            <span>{tab.charAt(0).toUpperCase() + tab.slice(1)}</span>
            {tab === 'tools' && config.tools.length > 0 && (
              <span className="badge">{config.tools.length}</span>
            )}
            {tab === 'mcp' && config.mcpServers.filter(s => s.enabled).length > 0 && (
              <span className="badge">{config.mcpServers.filter(s => s.enabled).length}</span>
            )}
          </button>
        ))}
      </nav>

      {/* Content */}
      <main className="builder-content">
        {/* Prompt Tab */}
        {activeTab === 'prompt' && (
          <div className="tab-panel prompt-panel">
            <div className="form-section">
              <label>System Prompt</label>
              <textarea
                value={config.systemPrompt}
                onChange={e => updateConfig({ systemPrompt: e.target.value })}
                placeholder="Você é um assistente que ajuda com..."
                rows={10}
              />
            </div>

            <div className="form-row">
              <div className="form-section">
                <label>Provider</label>
                <div className="select-wrapper">
                  <select
                    value={config.provider.type}
                    onChange={e => handleProviderTypeChange(e.target.value as any)}
                  >
                    <option value="openai">OpenAI (GPT-4)</option>
                    <option value="anthropic">Anthropic (Claude)</option>
                    <option value="zai">Z.ai (GLM-4)</option>
                    <option value="groq">Groq (Llama)</option>
                    <option value="custom">Custom</option>
                  </select>
                  <ChevronDownIcon />
                </div>
              </div>
            </div>

            <div className="form-row two-cols">
              <div className="form-section">
                <label>Base URL</label>
                <input
                  value={config.provider.baseUrl}
                  onChange={e => updateConfig({ provider: { ...config.provider, baseUrl: e.target.value } })}
                  placeholder="https://api.openai.com/v1"
                />
              </div>
              <div className="form-section">
                <label>Model</label>
                <input
                  value={config.provider.model}
                  onChange={e => updateConfig({ provider: { ...config.provider, model: e.target.value } })}
                  placeholder="gpt-4o-mini"
                />
              </div>
            </div>

            <div className="form-section">
              <label>API Key</label>
              <div className="input-with-icon">
                <input
                  type="password"
                  value={config.provider.apiKey}
                  onChange={e => updateConfig({ provider: { ...config.provider, apiKey: e.target.value } })}
                  placeholder="sk-..."
                />
                <KeyIcon />
              </div>
            </div>
          </div>
        )}

        {/* Tools Tab */}
        {activeTab === 'tools' && (
          <div className="tab-panel">
            <div className="panel-header">
              <h3>Custom Tools</h3>
              <button onClick={addTool} className="btn primary small">
                <PlusIcon /> Adicionar Tool
              </button>
            </div>

            {config.tools.length === 0 ? (
              <div className="empty-state">
                <WrenchIcon size={48} />
                <p>Nenhuma tool cadastrada</p>
                <span>Clique em "+ Adicionar Tool" para criar sua primeira tool</span>
              </div>
            ) : (
              <div className="items-list">
                {config.tools.map(tool => (
                  <div key={tool.id} className="item-card">
                    <div className="item-info">
                      <div className="item-icon">
                        <CodeIcon />
                      </div>
                      <div className="item-details">
                        <span className="item-name">{tool.name}</span>
                        <span className="item-desc">{tool.description || 'Sem descrição'}</span>
                      </div>
                    </div>
                    <div className="item-actions">
                      {tool.awaitConfirm && (
                        <span className="tag warning">Confirmação</span>
                      )}
                      <button onClick={() => setEditingTool(tool)} className="btn icon">
                        <EditIcon />
                      </button>
                      <button onClick={() => deleteTool(tool.id)} className="btn icon danger">
                        <TrashIcon />
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* MCP Tab */}
        {activeTab === 'mcp' && (
          <div className="tab-panel">
            <div className="panel-header">
              <h3>MCP Servers</h3>
              <button onClick={addMcpServer} className="btn primary small">
                <PlusIcon /> Adicionar Server
              </button>
            </div>

            {config.mcpServers.length === 0 ? (
              <div className="empty-state">
                <ServerIcon size={48} />
                <p>Nenhum MCP server configurado</p>
                <span>Adicione MCP servers para expandir as capacidades do agent</span>
              </div>
            ) : (
              <div className="items-list">
                {config.mcpServers.map(server => (
                  <div key={server.id} className={`item-card ${!server.enabled ? 'disabled' : ''}`}>
                    <div className="item-info">
                      <label className="toggle">
                        <input
                          type="checkbox"
                          checked={server.enabled}
                          onChange={() => saveMcpServer({ ...server, enabled: !server.enabled })}
                        />
                        <span className="toggle-slider" />
                      </label>
                      <div className="item-details">
                        <span className="item-name">{server.name}</span>
                        <span className="item-desc mono">{server.command} {server.args.join(' ')}</span>
                      </div>
                    </div>
                    <div className="item-actions">
                      <button onClick={() => setEditingMcp(server)} className="btn icon">
                        <EditIcon />
                      </button>
                      <button onClick={() => deleteMcpServer(server.id)} className="btn icon danger">
                        <TrashIcon />
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}

            <div className="presets-section">
              <h4>MCP Servers Populares</h4>
              <div className="presets-grid">
                {[
                  { name: 'Filesystem', args: '@modelcontextprotocol/server-filesystem ./data' },
                  { name: 'Postgres', args: '@modelcontextprotocol/server-postgres' },
                  { name: 'GitHub', args: '@modelcontextprotocol/server-github' },
                  { name: 'Slack', args: '@modelcontextprotocol/server-slack' },
                  { name: 'SQLite', args: '@modelcontextprotocol/server-sqlite' },
                ].map(preset => (
                  <button
                    key={preset.name}
                    onClick={() => {
                      setEditingMcp({
                        id: crypto.randomUUID(),
                        name: preset.name,
                        command: 'npx',
                        args: ['-y', preset.args.split(' ')[0], ...(preset.args.split(' ').slice(1) || [])],
                        env: {},
                        enabled: true,
                      });
                    }}
                    className="preset-btn"
                  >
                    <PlusIcon size={14} /> {preset.name}
                  </button>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* Settings Tab */}
        {activeTab === 'settings' && (
          <div className="tab-panel settings-panel">
            <div className="setting-card">
              <div className="setting-header">
                <label>Temperature</label>
                <span className="setting-value">{config.settings.temperature}</span>
              </div>
              <input
                type="range"
                min="0"
                max="2"
                step="0.1"
                value={config.settings.temperature}
                onChange={e => updateConfig({ settings: { ...config.settings, temperature: parseFloat(e.target.value) } })}
                className="slider"
              />
              <div className="slider-labels">
                <span>Preciso</span>
                <span>Criativo</span>
              </div>
            </div>

            <div className="setting-card">
              <div className="setting-header">
                <label>Max Iterations</label>
                <span className="setting-desc">Tool calling loop</span>
              </div>
              <input
                type="number"
                min="1"
                max="20"
                value={config.settings.maxIterations}
                onChange={e => updateConfig({ settings: { ...config.settings, maxIterations: parseInt(e.target.value) } })}
                className="number-input"
              />
            </div>

            <div className="setting-card">
              <div className="setting-header">
                <label>History Size</label>
                <span className="setting-desc">Mensagens mantidas no contexto</span>
              </div>
              <input
                type="number"
                min="5"
                max="100"
                value={config.settings.historySize}
                onChange={e => updateConfig({ settings: { ...config.settings, historySize: parseInt(e.target.value) } })}
                className="number-input"
              />
            </div>
          </div>
        )}
      </main>

      {/* Tool Editor Modal */}
      {editingTool && (
        <div className="modal-overlay" onClick={() => setEditingTool(null)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>{config.tools.find(t => t.id === editingTool.id) ? 'Editar' : 'Nova'} Tool</h3>
              <button onClick={() => setEditingTool(null)} className="btn icon">
                <CloseIcon />
              </button>
            </div>

            <div className="modal-body">
              <div className="form-section">
                <label>Nome *</label>
                <input
                  value={editingTool.name}
                  onChange={e => setEditingTool({ ...editingTool, name: e.target.value })}
                  placeholder="create_booking"
                  className="mono"
                />
              </div>

              <div className="form-section">
                <label>Descrição *</label>
                <input
                  value={editingTool.description}
                  onChange={e => setEditingTool({ ...editingTool, description: e.target.value })}
                  placeholder="Cria um novo agendamento"
                />
              </div>

              <div className="form-section">
                <label>Código (execute function)</label>
                <textarea
                  value={editingTool.code}
                  onChange={e => setEditingTool({ ...editingTool, code: e.target.value })}
                  placeholder="async (args) => { return { success: true }; }"
                  className="code-editor"
                  rows={8}
                />
              </div>

              <label className="checkbox-label">
                <input
                  type="checkbox"
                  checked={editingTool.awaitConfirm}
                  onChange={e => setEditingTool({ ...editingTool, awaitConfirm: e.target.checked })}
                />
                <span className="checkbox-custom" />
                <span>Exige confirmação do usuário</span>
              </label>

              {editingTool.awaitConfirm && (
                <div className="form-section">
                  <label>Mensagem de Confirmação</label>
                  <input
                    value={editingTool.confirmMessage}
                    onChange={e => setEditingTool({ ...editingTool, confirmMessage: e.target.value })}
                    placeholder="Tem certeza que deseja executar esta ação?"
                  />
                </div>
              )}
            </div>

            <div className="modal-footer">
              <button onClick={() => setEditingTool(null)} className="btn secondary">Cancelar</button>
              <button onClick={() => saveTool(editingTool)} className="btn primary">Salvar</button>
            </div>
          </div>
        </div>
      )}

      {/* MCP Editor Modal */}
      {editingMcp && (
        <div className="modal-overlay" onClick={() => setEditingMcp(null)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>{config.mcpServers.find(s => s.id === editingMcp.id) ? 'Editar' : 'Novo'} MCP Server</h3>
              <button onClick={() => setEditingMcp(null)} className="btn icon">
                <CloseIcon />
              </button>
            </div>

            <div className="modal-body">
              <div className="form-section">
                <label>Nome *</label>
                <input
                  value={editingMcp.name}
                  onChange={e => setEditingMcp({ ...editingMcp, name: e.target.value })}
                  placeholder="Filesystem"
                />
              </div>

              <div className="form-section">
                <label>Comando</label>
                <input
                  value={editingMcp.command}
                  onChange={e => setEditingMcp({ ...editingMcp, command: e.target.value })}
                  placeholder="npx"
                  className="mono"
                />
              </div>

              <div className="form-section">
                <label>Argumentos (separados por espaço)</label>
                <input
                  value={editingMcp.args.join(' ')}
                  onChange={e => setEditingMcp({ ...editingMcp, args: e.target.value.split(' ').filter(Boolean) })}
                  placeholder="-y @modelcontextprotocol/server-filesystem ./data"
                  className="mono"
                />
              </div>

              <div className="form-section">
                <label>Environment Variables (KEY=value, uma por linha)</label>
                <textarea
                  value={Object.entries(editingMcp.env).map(([k, v]) => `${k}=${v}`).join('\n')}
                  onChange={e => {
                    const env: Record<string, string> = {};
                    e.target.value.split('\n').forEach(line => {
                      const [key, ...vals] = line.split('=');
                      if (key?.trim()) env[key.trim()] = vals.join('=').trim();
                    });
                    setEditingMcp({ ...editingMcp, env });
                  }}
                  placeholder="GITHUB_TOKEN=xxx&#10;API_KEY=yyy"
                  className="mono"
                  rows={4}
                />
              </div>
            </div>

            <div className="modal-footer">
              <button onClick={() => setEditingMcp(null)} className="btn secondary">Cancelar</button>
              <button onClick={() => saveMcpServer(editingMcp)} className="btn primary">Salvar</button>
            </div>
          </div>
        </div>
      )}

      <style>{builderStyles}</style>
    </div>
  );
}

