/**
 * @guilherme/agent-sdk/react/useChat
 *
 * Hook for managing chat conversations with streaming support.
 */

import { useState, useCallback, useRef } from 'react';

export interface ChatMessage {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  /** Tool calls made in this message */
  toolCalls?: Array<{
    id: string;
    name: string;
    args: any;
    result?: any;
  }>;
  /** Whether this message is still being streamed */
  isStreaming?: boolean;
  /** Status steps shown during processing */
  statusSteps?: string[];
  /** Error if message failed */
  error?: Error;
}

export interface UseChatOptions {
  /** API endpoint (default: '/api/chat') */
  api?: string;
  /** Session ID for history persistence */
  sessionId?: string;
  /** Initial messages */
  initialMessages?: ChatMessage[];
  /** Callback when message is sent */
  onMessageSent?: (message: string) => void;
  /** Callback when response is received */
  onResponse?: (message: ChatMessage) => void;
  /** Callback on error */
  onError?: (error: Error) => void;
  /** Callback when tool is executed */
  onToolCall?: (toolCall: { name: string; args: any; result: any }) => void;
  /** Custom headers */
  headers?: Record<string, string>;
  /** Custom body fields */
  body?: Record<string, any>;
}

export interface UseChatReturn {
  /** Array of chat messages */
  messages: ChatMessage[];
  /** Current input value */
  input: string;
  /** Set input value */
  setInput: (value: string) => void;
  /** Whether a request is in progress */
  isLoading: boolean;
  /** Current error */
  error: Error | null;
  /** Send a message */
  sendMessage: (content?: string) => Promise<void>;
  /** Regenerate last assistant message */
  regenerate: () => Promise<void>;
  /** Stop current streaming */
  stop: () => void;
  /** Set messages directly */
  setMessages: (messages: ChatMessage[] | ((prev: ChatMessage[]) => ChatMessage[])) => void;
  /** Clear all messages */
  clearMessages: () => void;
  /** Handle input change (for form integration) */
  handleInputChange: (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => void;
  /** Handle form submit (for form integration) */
  handleSubmit: (e: React.FormEvent) => void;
}

function generateId(): string {
  return `${Date.now()}-${Math.random().toString(36).slice(2, 11)}`;
}

/**
 * Hook for managing chat conversations with streaming support
 *
 * @example
 * ```tsx
 * function Chat() {
 *   const {
 *     messages,
 *     input,
 *     handleInputChange,
 *     handleSubmit,
 *     isLoading,
 *   } = useChat({ api: '/api/chat' });
 *
 *   return (
 *     <div>
 *       {messages.map(m => (
 *         <div key={m.id}>{m.role}: {m.content}</div>
 *       ))}
 *       <form onSubmit={handleSubmit}>
 *         <input value={input} onChange={handleInputChange} />
 *         <button type="submit" disabled={isLoading}>Send</button>
 *       </form>
 *     </div>
 *   );
 * }
 * ```
 */
export function useChat(options: UseChatOptions = {}): UseChatReturn {
  const {
    api = '/api/chat',
    sessionId = generateId(),
    initialMessages = [],
    onMessageSent,
    onResponse,
    onError,
    headers,
    body,
  } = options;

  const [messages, setMessages] = useState<ChatMessage[]>(initialMessages);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<Error | null>(null);

  const abortControllerRef = useRef<AbortController | null>(null);

  const sendMessage = useCallback(async (content?: string) => {
    const messageContent = content ?? input;
    if (!messageContent.trim() || isLoading) return;

    const userMessage: ChatMessage = {
      id: generateId(),
      role: 'user',
      content: messageContent,
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);
    setError(null);

    // Create placeholder for assistant message
    const assistantId = generateId();
    setMessages(prev => [...prev, {
      id: assistantId,
      role: 'assistant',
      content: '',
      isStreaming: true,
    }]);

    abortControllerRef.current = new AbortController();

    try {
      const response = await fetch(api, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          ...headers,
        },
        body: JSON.stringify({
          message: messageContent,
          sessionId,
          ...body,
        }),
        signal: abortControllerRef.current.signal,
      });

      if (!response.ok) {
        throw new Error(`API Error: ${response.status}`);
      }

      const reader = response.body!.getReader();
      const decoder = new TextDecoder();
      let buffer = '';
      let toolCalls: any[] = [];
      let statusSteps: string[] = [];

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop() ?? '';

        for (const line of lines) {
          if (!line.startsWith('data: ')) continue;
          const data = JSON.parse(line.slice(6));

          switch (data.type) {
            case 'token':
              setMessages(prev => prev.map(m =>
                m.id === assistantId
                  ? { ...m, content: m.content + data.content }
                  : m
              ));
              break;

            case 'status':
              statusSteps.push(data.text);
              setMessages(prev => prev.map(m =>
                m.id === assistantId
                  ? { ...m, statusSteps: [...statusSteps] }
                  : m
              ));
              break;

            case 'tool_call':
              toolCalls.push(data.toolCall);
              break;

            case 'done':
              const finalToolCalls = toolCalls.length > 0 ? toolCalls : (data.toolCalls ?? []);
              setMessages(prev => prev.map(m =>
                m.id === assistantId
                  ? { ...m, isStreaming: false, toolCalls: finalToolCalls }
                  : m
              ));
              setMessages(prev => {
                const assistantMsg = prev.find(m => m.id === assistantId);
                if (assistantMsg) onResponse?.(assistantMsg);
                return prev;
              });
              break;

            case 'error':
              throw new Error(data.error);
          }
        }
      }

      onMessageSent?.(messageContent);
    } catch (err) {
      if (err instanceof Error && err.name === 'AbortError') {
        // User aborted, don't treat as error
        return;
      }
      const error = err instanceof Error ? err : new Error(String(err));
      setError(error);
      onError?.(error);
      setMessages(prev => prev.map(m =>
        m.id === assistantId
          ? { ...m, isStreaming: false, error }
          : m
      ));
    } finally {
      setIsLoading(false);
      abortControllerRef.current = null;
    }
  }, [api, sessionId, input, isLoading, headers, body, onMessageSent, onResponse, onError]);

  const regenerate = useCallback(async () => {
    // Find last user message and resend
    const lastUserIdx = messages.findLastIndex(m => m.role === 'user');
    if (lastUserIdx === -1) return;

    const lastUserMessage = messages[lastUserIdx];
    // Remove everything after last user message
    setMessages(prev => prev.slice(0, lastUserIdx));
    await sendMessage(lastUserMessage.content);
  }, [messages, sendMessage]);

  const stop = useCallback(() => {
    abortControllerRef.current?.abort();
  }, []);

  const clearMessages = useCallback(() => {
    setMessages([]);
  }, []);

  const handleInputChange = useCallback((e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setInput(e.target.value);
  }, []);

  const handleSubmit = useCallback((e: React.FormEvent) => {
    e.preventDefault();
    sendMessage();
  }, [sendMessage]);

  return {
    messages,
    input,
    setInput,
    isLoading,
    error,
    sendMessage,
    regenerate,
    stop,
    setMessages,
    clearMessages,
    handleInputChange,
    handleSubmit,
  };
}
